def generate_issues():
    if st.session_state.issues:
        return st.session_state.issues
    random.seed(42)
    sources = ["Booking Engine","Payment Gateway","AWS Lambda","ECS Service","RDS Database",
               "Kafka Consumer","Auth Service","CDN","Load Balancer","API Gateway",
               "S3 Storage","ElastiCache","SQS Queue","Notification Service"]
    types   = list(RUNBOOKS.keys()) + [
        "OutOfMemoryError","HTTP 500 Internal Server Error","HTTP 503 Service Unavailable",
        "Disk Space Critical (<5%)","Unhealthy ECS Task","S3 Bucket Access Denied","Lambda Cold Start Spike"]
    crits   = ["CRITICAL","CRITICAL","HIGH","HIGH","HIGH","MEDIUM","MEDIUM","MEDIUM","LOW","INFO"]
    issues  = []
    base    = datetime.now()
    for i in range(1, 35):
        crit = random.choice(crits)
        src  = random.choice(sources)
        err  = random.choice(types)
        dt   = base - timedelta(minutes=random.randint(5, 2880))
        res_dt = None
        status = random.choice(["Open","Open","In Progress","Resolved"])
        if status == "Resolved":
            # resolved sometime after detection
            res_dt = (dt + timedelta(minutes=random.randint(
                15, SLA_HOURS[crit]*60 + 120))).strftime("%Y-%m-%d %H:%M:%S")
        issues.append({
            "id": f"ISS-{1000+i}", "title": f"{err} in {src}",
            "source": src, "type": err, "criticality": crit,
            "timestamp": dt.strftime("%Y-%m-%d %H:%M:%S"),
            "resolved_at": res_dt,
            "status": status, "jira": None,
            "details": (f"Auto-detected: {err} in {src}. "
                        f"Occurrences/30min: {random.randint(1,50)}. "
                        f"Affected requests: {random.randint(10,5000)}. "
                        f"Environment: Production (ca-central-1)."),
            "log_snippet": (f"[ERROR] {dt.strftime('%H:%M:%S')} [{src.lower().replace(' ','-')}] "
                            f"{err} — RequestID: req-{random.randint(100000,999999)}"),
            "recommended_action": RUNBOOKS.get(err, {}).get("steps", ["Review logs and escalate."])[0],
            "week": "current" if dt > base - timedelta(days=7) else "previous",
        })
    st.session_state.issues = sorted(
        issues, key=lambda x: ({"CRITICAL":0,"HIGH":1,"MEDIUM":2,"LOW":3,"INFO":4}[x["criticality"]], x["timestamp"]))
    return st.session_state.issues


def generate_logs():
    if st.session_state.logs:
        return st.session_state.logs
    random.seed(99)
    levels   = ["ERROR","ERROR","WARN","INFO","INFO","INFO","DEBUG"]
    services = ["booking-engine","payment-gateway","auth-service","ecs-worker",
                "lambda-processor","api-gateway","notification-svc","cache-service"]
    messages = [
        "Request timeout after 30000ms", "Connection pool exhausted (max=50)",
        "Retry attempt 3/3 failed — circuit breaker tripped",
        "Response time exceeded SLA threshold (>2000ms)",
        "Successfully processed 1245 records",
        "Health check passed — all dependencies reachable",
        "Cache miss ratio at 45% — consider warming strategy",
        "DB query slow: 2341ms for SELECT on transactions table",
        "SSL handshake failed with upstream service",
        "Memory usage at 89% — approaching container limit",
        "SQS queue depth: 12450 messages — consumer falling behind",
        "Circuit breaker OPEN for payment-gateway",
        "ECS task unhealthy — failing ALB health checks",
        "S3 PutObject failed: AccessDenied",
        "Lambda duration: 28941ms — approaching 30s timeout",
        "Auto Scaling triggered: scaling out from 2 to 4 tasks",
        "RDS failover initiated — switching to replica",
        "CloudWatch alarm: ALARM for CPUUtilization",
        "Kafka consumer lag: 85000 messages on topic prod-events",
        "ALB 5xx error rate: 12.4% in last 5 minutes",
    ]
    logs = []
    base = datetime.now()
    for i in range(300):
        dt = base - timedelta(seconds=random.randint(0, 604800))  # 7 days
        logs.append({
            "timestamp": dt.strftime("%Y-%m-%d %H:%M:%S"),
            "level":     random.choice(levels),
            "service":   random.choice(services),
            "message":   random.choice(messages),
            "request_id": f"req-{random.randint(100000,999999)}",
            "week":      "current" if dt > base - timedelta(days=7) else "previous",
        })
    st.session_state.logs = sorted(logs, key=lambda x: x["timestamp"], reverse=True)
    return st.session_state.logs


