def build_correlations():
    """Group related issues into incident correlation groups."""
    if st.session_state.correlations:
        return st.session_state.correlations
    issues = generate_issues()
    open_issues = [i for i in issues if i["status"] != "Resolved"]

    groups = [
        {
            "group_id": "INC-001",
            "title": "Database Connectivity Cascade",
            "root_cause": "RDS Connection Pool Exhausted",
            "root_source": "RDS Database",
            "impact_chain": ["RDS Database", "Booking Engine", "Payment Gateway"],
            "description": "DB connection pool exhaustion causing cascading failures in booking and payment services.",
            "issue_ids": [i["id"] for i in open_issues if i["source"] in ("RDS Database","Booking Engine","Payment Gateway")][:5],
            "criticality": "CRITICAL",
            "confidence": 94,
            "detected": (datetime.now() - timedelta(minutes=45)).strftime("%Y-%m-%d %H:%M"),
            "suggested_fix": "1. Increase RDS max_connections parameter\n2. Add RDS Proxy for connection pooling\n3. Scale booking-engine tasks to reduce per-instance load",
        },
        {
            "group_id": "INC-002",
            "title": "Auth Service Degradation",
            "root_cause": "Auth Service ECS Task Failure",
            "root_source": "Auth Service",
            "impact_chain": ["Auth Service", "API Gateway", "Booking Engine"],
            "description": "Auth service task crash causing authentication failures across API gateway and booking engine.",
            "issue_ids": [i["id"] for i in open_issues if i["source"] in ("Auth Service","API Gateway")][:4],
            "criticality": "HIGH",
            "confidence": 87,
            "detected": (datetime.now() - timedelta(minutes=22)).strftime("%Y-%m-%d %H:%M"),
            "suggested_fix": "1. Force new ECS deployment for auth-service\n2. Check task logs for OOM or crash reason\n3. Increase task memory allocation",
        },
        {
            "group_id": "INC-003",
            "title": "Queue Processing Backlog",
            "root_cause": "Kafka Consumer Lag Spike",
            "root_source": "Kafka Consumer",
            "impact_chain": ["Kafka Consumer", "Notification Service", "SQS Queue"],
            "description": "Consumer lag spike causing notification delays and SQS backlog buildup.",
            "issue_ids": [i["id"] for i in open_issues if i["source"] in ("Kafka Consumer","Notification Service","SQS Queue")][:3],
            "criticality": "MEDIUM",
            "confidence": 78,
            "detected": (datetime.now() - timedelta(hours=1, minutes=15)).strftime("%Y-%m-%d %H:%M"),
            "suggested_fix": "1. Scale Kafka consumer group\n2. Check for poison messages in DLQ\n3. Increase SQS visibility timeout",
        },
    ]
    st.session_state.correlations = groups
    return groups


