def get_secret(key, fallback=""):
    try:
        return st.secrets.get(key, fallback) or fallback
    except Exception:
        return fallback


def create_jira_ticket(issue: dict) -> tuple:
    try:
        jira_url   = get_secret("JIRA_URL")
        jira_user  = get_secret("JIRA_USER")
        jira_token = get_secret("JIRA_TOKEN")
        jira_proj  = get_secret("JIRA_PROJECT", "AC")
        priority_map = {"CRITICAL":"Highest","HIGH":"High","MEDIUM":"Medium","LOW":"Low","INFO":"Lowest"}
        runbook = RUNBOOKS.get(issue["type"], {})
        runbook_text = "\n".join(runbook.get("steps",[])) if runbook else "No runbook available — review logs manually."
        desc = (
            f"Issue ID: {issue['id']}\nSource System: {issue['source']}\n"
            f"Error Type: {issue['type']}\nCriticality: {issue['criticality']}\n"
            f"Detected At: {issue['timestamp']}\n\nDetails:\n{issue['details']}\n\n"
            f"Log Snippet:\n{issue['log_snippet']}\n\n"
            f"Runbook — {runbook.get('title','General')}:\n{runbook_text}\n\n"
            f"Owner: {runbook.get('owner','Platform Team')}\n"
            f"---\nAuto-created by Air Canada Support System (Infosys)"
        )
        summary = f"[{issue['criticality']}] {issue['title']}"
        record = {
            "ticket": None, "issue_id": issue["id"], "title": summary,
            "source": issue["source"], "criticality": issue["criticality"],
            "created": datetime.now().strftime("%Y-%m-%d %H:%M"),
            "description": desc, "priority": priority_map.get(issue["criticality"],"Medium"),
            "runbook": runbook.get("title","—"), "runbook_owner": runbook.get("owner","—"),
        }
        if not all([jira_url, jira_user, jira_token]):
            ticket_id = f"AC-{random.randint(3000,9999)}"
            record.update({"ticket": ticket_id, "status":"Demo (configure Jira secrets)",
                           "jira_url": f"https://yourcompany.atlassian.net/browse/{ticket_id}", "mode":"demo"})
            st.session_state.jira_tickets.append(record)
            audit("JIRA_CREATED", f"{ticket_id} for {issue['id']} (demo)", "JIRA")
            return True, ticket_id
        payload = {"fields": {
            "project": {"key": jira_proj}, "summary": summary,
            "description": {"type":"doc","version":1,"content":[{"type":"paragraph","content":[{"type":"text","text":desc}]}]},
            "issuetype": {"name":"Bug"}, "priority": {"name": priority_map.get(issue["criticality"],"Medium")},
        }}
        resp = requests.post(f"{jira_url}/rest/api/3/issue", json=payload,
                             auth=(jira_user, jira_token),
                             headers={"Content-Type":"application/json"}, timeout=10)
        if resp.status_code == 201:
            ticket_id = resp.json()["key"]
            record.update({"ticket": ticket_id, "status":"Created",
                           "jira_url": f"{jira_url}/browse/{ticket_id}", "mode":"live"})
            st.session_state.jira_tickets.append(record)
            audit("JIRA_CREATED", f"{ticket_id} for {issue['id']} (live)", "JIRA")
            return True, ticket_id
        return False, f"Jira API {resp.status_code}: {resp.text[:150]}"
    except Exception as e:
        return False, str(e)


def send_alert_email(issue: dict, jira_ticket: str = None) -> tuple:
    try:
        smtp_host = get_secret("SMTP_HOST")
        smtp_port = int(get_secret("SMTP_PORT","587"))
        smtp_user = get_secret("SMTP_USER")
        smtp_pass = get_secret("SMTP_PASSWORD")
        recip_raw = get_secret("ALERT_EMAILS") or st.session_state.alert_emails
        recipients = [e.strip() for e in recip_raw.split(",") if e.strip()]
        if not recipients:
            return False, "No recipients — add ALERT_EMAILS to secrets.toml or Settings tab"
        crit_emoji = {"CRITICAL":"🔴","HIGH":"🟠","MEDIUM":"🟡","LOW":"🔵","INFO":"🟢"}.get(issue["criticality"],"⚪")
        subject = f"{crit_emoji} [{issue['criticality']}] Air Canada Alert: {issue['title']}"
        runbook = RUNBOOKS.get(issue["type"],{})
        runbook_text = "\n  ".join(runbook.get("steps",[])) if runbook else "Review logs and escalate."
        jira_line = f"\nJira Ticket:  {jira_ticket}\nJira Link:    https://yourcompany.atlassian.net/browse/{jira_ticket}" if jira_ticket else "\nJira Ticket:  Pending"
        body = f"""Air Canada Support System — Automated Alert
{'='*62}
INCIDENT SUMMARY
  Issue ID:     {issue['id']}
  Title:        {issue['title']}
  Criticality:  {issue['criticality']}
  Source:       {issue['source']}
  Error Type:   {issue['type']}
  Detected:     {issue['timestamp']}
  Status:       {issue['status']}{jira_line}

DETAILS
  {issue['details']}

LOG SNIPPET
  {issue['log_snippet']}

RUNBOOK — {runbook.get('title','General Guidance')}
  Owner: {runbook.get('owner','Platform Team')}
  {runbook_text}

{'='*62}
Auto-generated by Air Canada Support System
Powered by Infosys Travel & Hospitality Initiative
Do not reply — manage incidents in the dashboard."""
        record = {
            "issue_id": issue["id"], "subject": subject,
            "to": ", ".join(recipients), "criticality": issue["criticality"],
            "source": issue["source"], "sent": datetime.now().strftime("%Y-%m-%d %H:%M"),
            "body": body, "jira": jira_ticket or "—",
        }
        if not all([smtp_host, smtp_user, smtp_pass]):
            record.update({"status":"Demo (configure SMTP secrets)", "mode":"demo"})
            st.session_state.email_log.append(record)
            audit("EMAIL_SENT", f"Demo to {', '.join(recipients)} for {issue['id']}", "EMAIL")
            return True, f"Demo — would send to: {', '.join(recipients)}"
        msg = MIMEMultipart()
        msg["From"] = smtp_user; msg["To"] = ", ".join(recipients); msg["Subject"] = subject
        msg.attach(MIMEText(body,"plain"))
        with smtplib.SMTP(smtp_host, smtp_port) as s:
            s.starttls(); s.login(smtp_user, smtp_pass); s.sendmail(smtp_user, recipients, msg.as_string())
        record.update({"status":"Sent","mode":"live"})
        st.session_state.email_log.append(record)
        audit("EMAIL_SENT", f"Live to {', '.join(recipients)} for {issue['id']}", "EMAIL")
        return True, f"Sent to {', '.join(recipients)}"
    except Exception as e:
        return False, str(e)


def send_slack_alert(issue: dict, jira_ticket: str = None) -> tuple:
    try:
        webhook = get_secret("SLACK_WEBHOOK_URL") or st.session_state.slack_webhook
        if not webhook:
            return False, "No Slack webhook configured"
        crit_color = {"CRITICAL":"#C62828","HIGH":"#D84315","MEDIUM":"#F57C00","LOW":"#1565C0","INFO":"#2E7D32"}.get(issue["criticality"],"#888")
        payload = {"attachments":[{"color": crit_color, "blocks":[
            {"type":"header","text":{"type":"plain_text","text":f"🍁 [{issue['criticality']}] {issue['title']}"}},
            {"type":"section","fields":[
                {"type":"mrkdwn","text":f"*Source:* {issue['source']}"},
                {"type":"mrkdwn","text":f"*Detected:* {issue['timestamp']}"},
                {"type":"mrkdwn","text":f"*Issue ID:* {issue['id']}"},
                {"type":"mrkdwn","text":f"*Jira:* {jira_ticket or 'Pending'}"},
            ]},
            {"type":"section","text":{"type":"mrkdwn","text":f"*Details:* {issue['details'][:200]}"}},
        ]}]}
        resp = requests.post(webhook, json=payload, timeout=5)
        if resp.status_code == 200:
            audit("SLACK_SENT", f"Alert for {issue['id']} ({issue['criticality']})", "SLACK")
            return True, "Slack notification sent"
        return False, f"Slack error {resp.status_code}"
    except Exception as e:
        return False, str(e)


def send_teams_alert(issue: dict, jira_ticket: str = None) -> tuple:
    try:
        webhook = get_secret("TEAMS_WEBHOOK_URL") or st.session_state.teams_webhook
        if not webhook:
            return False, "No Teams webhook configured"
        crit_color = {"CRITICAL":"attention","HIGH":"warning","MEDIUM":"accent","LOW":"good","INFO":"good"}.get(issue["criticality"],"default")
        payload = {
            "type": "message",
            "attachments": [{"contentType":"application/vnd.microsoft.card.adaptive","content":{
                "$schema":"http://adaptivecards.io/schemas/adaptive-card.json","type":"AdaptiveCard","version":"1.4",
                "body":[
                    {"type":"TextBlock","size":"Large","weight":"Bolder","text":f"🍁 [{issue['criticality']}] Air Canada Alert","color":crit_color},
                    {"type":"TextBlock","text":issue['title'],"wrap":True},
                    {"type":"FactSet","facts":[
                        {"title":"Source","value":issue['source']},
                        {"title":"Detected","value":issue['timestamp']},
                        {"title":"Issue ID","value":issue['id']},
                        {"title":"Jira","value":jira_ticket or "Pending"},
                    ]},
                ]
            }}]
        }
        resp = requests.post(webhook, json=payload, timeout=5)
        if resp.status_code in (200,202):
            audit("TEAMS_SENT", f"Alert for {issue['id']} ({issue['criticality']})", "TEAMS")
            return True, "Teams notification sent"
        return False, f"Teams error {resp.status_code}"
    except Exception as e:
        return False, str(e)


def fire_all_notifications(issue: dict, jira_ticket: str = None):
    """Fire all enabled notification channels for an issue."""
    results = {}
    if st.session_state.auto_email:
        ok, msg = send_alert_email(issue, jira_ticket)
        results["email"] = (ok, msg)
    if st.session_state.auto_slack:
        ok, msg = send_slack_alert(issue, jira_ticket)
        results["slack"] = (ok, msg)
    if st.session_state.auto_teams:
        ok, msg = send_teams_alert(issue, jira_ticket)
        results["teams"] = (ok, msg)
    return results


def auto_process_issues():
    """Auto-create Jira + notifications for CRITICAL/HIGH on login."""
    issues = generate_issues()
    for issue in issues:
        if issue["id"] in st.session_state.auto_processed_ids:
            continue
        if issue["criticality"] not in ("CRITICAL","HIGH"):
            continue
        if issue["status"] == "Resolved":
            continue
        jira_ticket = None
        if st.session_state.auto_jira and not issue.get("jira"):
            ok, result = create_jira_ticket(issue)
            if ok:
                issue["jira"] = result
                jira_ticket = result
        fire_all_notifications(issue, jira_ticket or issue.get("jira"))
        st.session_state.auto_processed_ids.add(issue["id"])


