def render_issues_dashboard():
    st.markdown('<div class="page-banner"><h2>🚨 Issues Dashboard</h2><p>Real-time detected issues across all systems — auto Jira, email, Slack & Teams</p></div>', unsafe_allow_html=True)
    issues = generate_issues()
    open_issues = [i for i in issues if i["status"] != "Resolved"]
    counts = {c: sum(1 for i in open_issues if i["criticality"]==c) for c in CRIT_COLORS}
    cols = st.columns(5)
    for col, (crit, color) in zip(cols, CRIT_COLORS.items()):
        with col:
            st.markdown(f'<div class="ac-card" style="border-top:4px solid {color};text-align:center;"><div style="font-size:2rem;font-weight:800;color:{color};">{counts[crit]}</div><div style="font-size:0.72rem;color:#64748B;text-transform:uppercase;letter-spacing:1px;">{crit}</div></div>', unsafe_allow_html=True)
    st.markdown("---")
    fc1,fc2,fc3,fc4 = st.columns(4)
    with fc1: filt_crit   = st.multiselect("Criticality", list(CRIT_COLORS.keys()), default=list(CRIT_COLORS.keys()), key="dash_crit")
    with fc2: filt_status = st.multiselect("Status", ["Open","In Progress","Resolved"], default=["Open","In Progress"], key="dash_status")
    with fc3: filt_src    = st.selectbox("Source", ["All"]+sorted(set(i["source"] for i in issues)), key="dash_src")
    with fc4: filt_type   = st.selectbox("Error Type", ["All"]+sorted(set(i["type"] for i in issues)), key="dash_type")
    filtered = [i for i in issues
                if i["criticality"] in filt_crit and i["status"] in filt_status
                and (filt_src=="All" or i["source"]==filt_src)
                and (filt_type=="All" or i["type"]==filt_type)]
    st.markdown(f"**Showing {len(filtered)} issues** — {sum(1 for i in filtered if i.get('jira'))} have Jira tickets")
    for issue in filtered:
        crit  = issue["criticality"]
        color = CRIT_COLORS[crit]
        icon  = {"CRITICAL":"🔴","HIGH":"🟠","MEDIUM":"🟡","LOW":"🔵","INFO":"🟢"}.get(crit,"⚪")
        has_jira = bool(issue.get("jira"))
        with st.expander(f"{icon} [{issue['id']}] {issue['title']}", expanded=(crit=="CRITICAL" and issue["status"]!="Resolved")):
            col_l, col_r = st.columns([3,1])
            with col_l:
                st.markdown(f'<span class="badge-{crit.lower()}">{crit}</span> &nbsp;<span style="font-size:0.75rem;color:#64748B;">📍 {issue["source"]} &nbsp;|&nbsp; 🕐 {issue["timestamp"]} &nbsp;|&nbsp; 📊 {issue["status"]}</span>', unsafe_allow_html=True)
                st.markdown(f"**Details:** {issue['details']}")
                st.code(issue["log_snippet"], language="text")
                runbook = RUNBOOKS.get(issue["type"],{})
                if runbook:
                    with st.expander(f"📖 Runbook: {runbook['title']}", expanded=False):
                        for step in runbook["steps"]:
                            st.markdown(f'<div class="runbook-step">{step}</div>', unsafe_allow_html=True)
                        st.markdown(f"**Owner:** {runbook['owner']}")
                if has_jira:
                    st.markdown(f"🎫 **Jira:** `{issue['jira']}`")
            with col_r:
                can_act = st.session_state.role in ["Admin","Manager","Analyst"]
                if not has_jira and can_act:
                    if st.button("🎫 Create Jira", key=f"jira_{issue['id']}"):
                        ok, result = create_jira_ticket(issue)
                        if ok:
                            issue["jira"] = result
                            st.success(f"✅ {result}")
                            fire_all_notifications(issue, result)
                        else:
                            st.error(f"❌ {result}")
                if st.button("📧 Notify", key=f"notif_{issue['id']}"):
                    send_alert_email(issue, issue.get("jira"))
                    if st.session_state.slack_webhook or get_secret("SLACK_WEBHOOK_URL"):
                        send_slack_alert(issue, issue.get("jira"))
                    st.success("✅ Notifications sent")
                if can_act and issue["status"] != "Resolved":
                    if st.button("✅ Resolve", key=f"resolve_{issue['id']}"):
                        issue["status"] = "Resolved"
                        issue["resolved_at"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
                        audit("ISSUE_RESOLVED", f"{issue['id']} — {issue['title']}", "INCIDENT")
                        st.rerun()


