def render_correlation():
    st.markdown('<div class="page-banner"><h2>🔗 Root Cause Correlation</h2><p>AI-powered grouping of related issues into incident clusters — eliminate duplicate triage</p></div>', unsafe_allow_html=True)
    groups = build_correlations()
    issues = generate_issues()
    issue_map = {i["id"]: i for i in issues}
    col_a, col_b, col_c = st.columns(3)
    col_a.metric("Active Incident Groups", len(groups))
    col_b.metric("Issues Correlated", sum(len(g["issue_ids"]) for g in groups))
    col_c.metric("Avg Confidence", f"{sum(g['confidence'] for g in groups)//len(groups)}%")
    st.markdown("---")
    for g in groups:
        color = CRIT_COLORS.get(g["criticality"],"#888")
        conf_bar = "█" * (g["confidence"]//10) + "░" * (10 - g["confidence"]//10)
        st.markdown(f"""
        <div class="corr-group">
            <div style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:8px;">
                <div>
                    <span style="font-size:1rem;font-weight:700;color:{color};">{g["group_id"]}: {g["title"]}</span>
                    <span class="badge-{g['criticality'].lower()}" style="margin-left:8px;">{g["criticality"]}</span>
                </div>
                <div style="font-size:0.72rem;color:#94A3B8;">
                    🕐 Detected: {g["detected"]} &nbsp;|&nbsp;
                    🎯 Confidence: <b>{g["confidence"]}%</b> {conf_bar}
                </div>
            </div>
            <div style="margin-top:8px;font-size:0.82rem;color:#64748B;">{g["description"]}</div>
            <div style="margin-top:8px;">
                <span style="font-size:0.72rem;font-weight:600;color:{color};">Root Cause: </span>
                <span style="font-size:0.72rem;">{g["root_cause"]}</span>
                <span style="font-size:0.72rem;color:#94A3B8;margin-left:12px;">Impact chain: </span>
                <span style="font-size:0.72rem;">{" → ".join(g["impact_chain"])}</span>
            </div>
        </div>""", unsafe_allow_html=True)
        with st.expander(f"🔍 Details — {len(g['issue_ids'])} correlated issues", expanded=False):
            c1, c2 = st.columns([2,1])
            with c1:
                st.markdown("**Correlated Issues:**")
                for iid in g["issue_ids"]:
                    issue = issue_map.get(iid)
                    if issue:
                        st.markdown(f"- `{iid}` — {issue['title']} [{issue['status']}]")
                st.markdown("**Suggested Fix:**")
                for line in g["suggested_fix"].split("\n"):
                    if line.strip():
                        st.markdown(f'<div class="runbook-step">{line}</div>', unsafe_allow_html=True)
            with c2:
                if st.button(f"🎫 Create Group Jira", key=f"grp_jira_{g['group_id']}"):
                    group_issue = {
                        "id": g["group_id"], "title": g["title"],
                        "source": g["root_source"], "type": "Incident Group",
                        "criticality": g["criticality"], "status": "Open",
                        "timestamp": g["detected"],
                        "details": f"{g['description']}\n\nImpact chain: {' → '.join(g['impact_chain'])}\nCorrelated issues: {', '.join(g['issue_ids'])}",
                        "log_snippet": f"Incident group {g['group_id']} — {len(g['issue_ids'])} correlated issues",
                        "recommended_action": g["suggested_fix"],
                    }
                    ok, result = create_jira_ticket(group_issue)
                    if ok:
                        st.success(f"✅ Group Jira: {result}")
                        fire_all_notifications(group_issue, result)
                    else:
                        st.error(f"❌ {result}")
                if st.button(f"📧 Alert Team", key=f"grp_email_{g['group_id']}"):
                    group_issue = {
                        "id": g["group_id"], "title": g["title"],
                        "source": g["root_source"], "type": "Incident Group",
                        "criticality": g["criticality"], "status": "Open",
                        "timestamp": g["detected"],
                        "details": g["description"],
                        "log_snippet": f"Impact: {' → '.join(g['impact_chain'])}",
                        "recommended_action": g["suggested_fix"],
                    }
                    fire_all_notifications(group_issue)
                    st.success("✅ Team notified")


