# TAB: SLA / MTTR
# ══════════════════════════════════════════════════════════════════════════════

def render_sla_mttr():
    st.markdown('<div class="page-banner"><h2>📏 SLA & MTTR Tracker</h2><p>Mean Time to Resolve vs SLA targets — measure your 50-60% efficiency improvement</p></div>', unsafe_allow_html=True)
    issues  = generate_issues()
    sla_targets = SLA_HOURS  # CRITICAL:1h, HIGH:4h, MEDIUM:8h, LOW:24h

    resolved = [i for i in issues if i["status"]=="Resolved" and i.get("resolved_at")]
    mttr_by_crit = {}
    breaches     = {}
    for crit in CRIT_COLORS:
        res = [i for i in resolved if i["criticality"]==crit]
        if res:
            minutes = []
            breach_count = 0
            for i in res:
                try:
                    dt_open = datetime.strptime(i["timestamp"],   "%Y-%m-%d %H:%M:%S")
                    dt_res  = datetime.strptime(i["resolved_at"], "%Y-%m-%d %H:%M:%S")
                    mins    = (dt_res - dt_open).total_seconds() / 60
                    minutes.append(mins)
                    if mins > sla_targets[crit] * 60:
                        breach_count += 1
                except Exception:
                    pass
            mttr_by_crit[crit] = sum(minutes)/len(minutes) if minutes else 0
            breaches[crit]     = breach_count
        else:
            mttr_by_crit[crit] = 0
            breaches[crit]     = 0

    # KPI row
    st.markdown("#### SLA Performance Summary")
    cols = st.columns(len(SLA_HOURS))
    for col, (crit, sla_h) in zip(cols, SLA_HOURS.items()):
        color   = CRIT_COLORS[crit]
        mttr_h  = mttr_by_crit.get(crit,0) / 60
        within  = mttr_h <= sla_h if mttr_h > 0 else True
        status  = "✅ Within SLA" if within else "⚠️ SLA Breach"
        with col:
            st.markdown(f"""
            <div class="ac-card" style="border-top:4px solid {color};text-align:center;">
                <div style="font-size:0.72rem;text-transform:uppercase;color:#64748B;letter-spacing:1px;">{crit}</div>
                <div style="font-size:1.6rem;font-weight:800;color:{color};">{mttr_h:.1f}h</div>
                <div style="font-size:0.68rem;color:#94A3B8;">MTTR vs {sla_h}h SLA</div>
                <div style="font-size:0.7rem;margin-top:4px;color:{'#2E7D32' if within else '#C62828'};font-weight:600;">{status}</div>
                <div style="font-size:0.68rem;color:#94A3B8;">{breaches.get(crit,0)} breach(es)</div>
            </div>""", unsafe_allow_html=True)

    st.markdown("---")
    r1c1, r1c2 = st.columns(2)
    with r1c1:
        # MTTR bar chart
        mttr_data = [{"Criticality": c, "MTTR (hours)": round(mttr_by_crit.get(c,0)/60,2),
                      "SLA (hours)": SLA_HOURS[c]} for c in CRIT_COLORS if mttr_by_crit.get(c,0) > 0]
        if mttr_data:
            df_mttr = pd.DataFrame(mttr_data)
            fig = go.Figure()
            fig.add_bar(x=df_mttr["Criticality"], y=df_mttr["MTTR (hours)"],
                        name="MTTR", marker_color=[CRIT_COLORS[c] for c in df_mttr["Criticality"]])
            fig.add_scatter(x=df_mttr["Criticality"], y=df_mttr["SLA (hours)"],
                            mode="markers+lines", name="SLA Target",
                            line=dict(color="#1565C0", dash="dash"), marker=dict(size=8))
            fig.update_layout(title="MTTR vs SLA Targets", height=320,
                              margin=dict(t=40,b=10,l=10,r=10), barmode="group")
            st.plotly_chart(fig, use_container_width=True)
        else:
            st.info("No resolved issues yet to calculate MTTR.")

    with r1c2:
        # Resolution rate over time
        df_issues = pd.DataFrame(issues)
        df_issues["date"] = pd.to_datetime(df_issues["timestamp"]).dt.date
        daily = df_issues.groupby(["date","status"]).size().reset_index(name="count")
        fig2 = px.line(daily, x="date", y="count", color="status",
                       title="Daily Issue Volume by Status",
                       color_discrete_map={"Open":AC_RED,"In Progress":"#F57C00","Resolved":"#2E7D32"})
        fig2.update_layout(height=320, margin=dict(t=40,b=10,l=10,r=10))
        st.plotly_chart(fig2, use_container_width=True)

    st.markdown("#### Issue Resolution Detail")
    res_df = pd.DataFrame([{
        "Issue ID": i["id"], "Title": i["title"][:50],
        "Criticality": i["criticality"], "Source": i["source"],
        "Opened": i["timestamp"], "Resolved": i.get("resolved_at","—"),
        "SLA (h)": SLA_HOURS.get(i["criticality"],"—"),
    } for i in resolved])
    if not res_df.empty:
        st.dataframe(res_df, use_container_width=True, hide_index=True)
    else:
        st.info("No resolved issues in current dataset.")


