def render_analytics():
    st.markdown('<div class="page-banner"><h2>📊 Analytics</h2><p>Issue trends, criticality distribution, source analysis & week-over-week comparison</p></div>', unsafe_allow_html=True)
    issues = generate_issues()
    df = pd.DataFrame(issues)
    df["timestamp"] = pd.to_datetime(df["timestamp"])
    df["date"] = df["timestamp"].dt.date
    df["hour"] = df["timestamp"].dt.hour

    curr_week = df[df["week"]=="current"]
    prev_week = df[df["week"]=="previous"]

    # Week-over-week KPIs
    st.markdown("#### Week-over-Week Comparison")
    wc1,wc2,wc3,wc4,wc5 = st.columns(5)
    for col, crit in zip([wc1,wc2,wc3,wc4,wc5], CRIT_COLORS):
        curr_n = len(curr_week[curr_week["criticality"]==crit])
        prev_n = len(prev_week[prev_week["criticality"]==crit])
        delta  = curr_n - prev_n
        with col:
            color = CRIT_COLORS[crit]
            arrow = "↑" if delta > 0 else "↓" if delta < 0 else "→"
            dcolor= "#C62828" if delta > 0 else "#2E7D32" if delta < 0 else "#888"
            st.markdown(f"""
            <div class="ac-card" style="border-top:4px solid {color};text-align:center;">
                <div style="font-size:0.68rem;text-transform:uppercase;color:#94A3B8;">{crit}</div>
                <div style="font-size:1.8rem;font-weight:800;color:{color};">{curr_n}</div>
                <div style="font-size:0.72rem;color:{dcolor};font-weight:600;">{arrow} {abs(delta)} vs last week</div>
            </div>""", unsafe_allow_html=True)

    st.markdown("---")
    r1c1,r1c2 = st.columns(2)
    with r1c1:
        fig = px.pie(df["criticality"].value_counts().reset_index().rename(columns={"criticality":"Criticality","count":"Count"}),
                     names="Criticality",values="Count",hole=0.4,title="Distribution by Criticality",
                     color="Criticality",color_discrete_map=CRIT_COLORS)
        fig.update_layout(height=320,margin=dict(t=40,b=10,l=10,r=10))
        st.plotly_chart(fig,use_container_width=True)
    with r1c2:
        src = df.groupby("source").size().reset_index(name="count").sort_values("count",ascending=True)
        fig2 = px.bar(src,x="count",y="source",orientation="h",title="Issues by Source",color_discrete_sequence=[AC_RED])
        fig2.update_layout(height=320,margin=dict(t=40,b=10,l=10,r=10),yaxis_title="",xaxis_title="Count")
        st.plotly_chart(fig2,use_container_width=True)

    r2c1,r2c2 = st.columns(2)
    with r2c1:
        # Week over week bar comparison
        curr_counts = curr_week["criticality"].value_counts().reset_index()
        curr_counts["week"] = "This Week"
        prev_counts = prev_week["criticality"].value_counts().reset_index()
        prev_counts["week"] = "Last Week"
        wow = pd.concat([curr_counts,prev_counts]).rename(columns={"criticality":"Criticality","count":"Count"})
        fig3 = px.bar(wow,x="Criticality",y="Count",color="week",barmode="group",
                      title="This Week vs Last Week",
                      color_discrete_map={"This Week":AC_RED,"Last Week":"#888"})
        fig3.update_layout(height=300,margin=dict(t=40,b=10,l=10,r=10))
        st.plotly_chart(fig3,use_container_width=True)
    with r2c2:
        hourly = df.groupby("hour").size().reset_index(name="count")
        fig4 = px.bar(hourly,x="hour",y="count",title="Issues by Hour of Day",color_discrete_sequence=[AC_RED])
        fig4.update_layout(height=300,margin=dict(t=40,b=10,l=10,r=10),xaxis_title="Hour",yaxis_title="Count")
        st.plotly_chart(fig4,use_container_width=True)

    # Top error types
    st.markdown("#### Top Error Types")
    type_counts = df["type"].value_counts().head(10).reset_index()
    type_counts.columns = ["Error Type","Count"]
    fig5 = px.bar(type_counts,x="Count",y="Error Type",orientation="h",
                  title="Top 10 Error Types (All Time)",color_discrete_sequence=["#D84315"])
    fig5.update_layout(height=350,margin=dict(t=40,b=10,l=10,r=10),yaxis_title="")
    st.plotly_chart(fig5,use_container_width=True)


