def render_runbooks():
    st.markdown('<div class="page-banner"><h2>📖 Runbook Library</h2><p>Step-by-step remediation guides — auto-attached to Jira tickets</p></div>', unsafe_allow_html=True)
    st.info(f"**{len(RUNBOOKS)} runbooks** available — automatically attached to Jira tickets when a matching error type is detected.")
    search_rb = st.text_input("🔍 Search runbooks", placeholder="e.g. timeout, memory, circuit breaker...")
    filtered_rb = {k:v for k,v in RUNBOOKS.items() if not search_rb or search_rb.lower() in k.lower() or search_rb.lower() in v["title"].lower()}
    for error_type, rb in filtered_rb.items():
        with st.expander(f"📖 {rb['title']}", expanded=False):
            col1, col2 = st.columns([3,1])
            with col1:
                st.markdown(f"**Error Type:** `{error_type}`")
                st.markdown("**Steps:**")
                for step in rb["steps"]:
                    st.markdown(f'<div class="runbook-step">{step}</div>', unsafe_allow_html=True)
            with col2:
                st.markdown(f"**Owner:** {rb['owner']}")
                st.markdown(f"**Trigger Severity:** {rb['severity_threshold']}+")
                issues = generate_issues()
                matching = [i for i in issues if i["type"]==error_type and i["status"]!="Resolved"]
                if matching:
                    st.markdown(f"**Active issues:** {len(matching)}")
                    for i in matching[:3]:
                        st.markdown(f"- `{i['id']}` [{i['criticality']}]")
                else:
                    st.markdown("✅ No active issues")
    st.markdown("---")
    st.markdown("#### ➕ Add Custom Runbook")
    with st.expander("Create new runbook", expanded=False):
        if st.session_state.role in ["Admin","Manager"]:
            rb_error = st.text_input("Error Type (must match log error exactly)")
            rb_title = st.text_input("Runbook Title")
            rb_owner = st.text_input("Owner Team")
            rb_steps_raw = st.text_area("Steps (one per line)")
            if st.button("💾 Save Runbook") and rb_error and rb_title:
                steps = [s.strip() for s in rb_steps_raw.splitlines() if s.strip()]
                RUNBOOKS[rb_error] = {"title":rb_title,"steps":steps,"owner":rb_owner or "Platform Team","severity_threshold":"MEDIUM"}
                audit("RUNBOOK_CREATED", f"{rb_title} for {rb_error}", "RUNBOOK")
                st.success(f"✅ Runbook '{rb_title}' saved")
                st.rerun()
        else:
            st.warning("Admin or Manager role required to create runbooks.")


