def render_ai_chat():
    st.markdown('<div class="page-banner"><h2>🤖 AI Assistant</h2><p>SRE-trained AI — ask about incidents, request runbooks, generate handover reports</p></div>', unsafe_allow_html=True)
    api_key = get_secret("ANTHROPIC_API_KEY") or st.text_input("🔑 Anthropic API Key", type="password", placeholder="sk-ant-...", key="chat_api")
    if not st.session_state.chat_history:
        st.session_state.chat_history = [{"role":"assistant","content":
            "👋 Hello! I'm your Air Canada SRE AI Assistant.\n\n"
            "I can help you with:\n- **Incident Analysis** — investigate and correlate issues\n"
            "- **Runbook Guidance** — step-by-step remediation\n"
            "- **Shift Handover** — generate shift summaries\n"
            "- **AWS Health** — interpret infrastructure metrics\n"
            "- **Trend Analysis** — identify recurring patterns\n\n"
            "What would you like to explore?"}]
    for msg in st.session_state.chat_history:
        if msg["role"]=="assistant":
            st.markdown(f'<div class="ai-bubble">🍁 <b>AC Support AI</b><br>{msg["content"].replace(chr(10),"<br>")}</div>', unsafe_allow_html=True)
        else:
            st.markdown(f'<div class="user-bubble">{msg["content"]}</div>', unsafe_allow_html=True)
    issues = generate_issues()
    open_crit = [i for i in issues if i["criticality"]=="CRITICAL" and i["status"]!="Resolved"]
    open_high = [i for i in issues if i["criticality"]=="HIGH"     and i["status"]!="Resolved"]
    corrs     = build_correlations()
    ctx = (f"System state: {len(open_crit)} CRITICAL, {len(open_high)} HIGH open issues. "
           f"{len(corrs)} active incident groups. "
           f"{len(st.session_state.jira_tickets)} Jira tickets created this session. "
           f"Most urgent: {open_crit[0]['title'] if open_crit else 'none'}.")
    user_input = st.chat_input("Ask about incidents, request a runbook, or say 'generate handover report'...")
    if user_input:
        st.session_state.chat_history.append({"role":"user","content":user_input})
        if api_key and api_key.startswith("sk-ant-"):
            try:
                import anthropic
                client = anthropic.Anthropic(api_key=api_key)
                system_prompt = (
                    "You are an expert SRE for Air Canada's enterprise systems. "
                    "You monitor AWS infrastructure, booking systems, payment gateways, auth services, and event-driven microservices. "
                    f"Current context: {ctx} "
                    "Provide concise, actionable guidance. Include specific AWS CLI commands when relevant. "
                    "When asked for a handover report, format it clearly with sections for Open Issues, Resolved, and Recommendations. "
                    "When asked for a runbook, provide numbered steps."
                )
                msgs = [{"role":m["role"],"content":m["content"]} for m in st.session_state.chat_history]
                resp = client.messages.create(model="claude-sonnet-4-20250514", max_tokens=1000, system=system_prompt, messages=msgs[-12:])
                reply = resp.content[0].text
            except Exception as e:
                reply = f"⚠️ AI error: {e}"
        else:
            q = user_input.lower()
            if any(w in q for w in ["handover","shift","summary","report"]):
                reply = (f"**Shift Summary — {datetime.now().strftime('%Y-%m-%d %H:%M')}**\n\n"
                         f"🔴 CRITICAL open: {len(open_crit)}\n"
                         f"🟠 HIGH open: {len(open_high)}\n"
                         f"🔗 Incident groups: {len(corrs)}\n"
                         f"🎫 Jira tickets created: {len(st.session_state.jira_tickets)}\n\n"
                         f"Most urgent: {open_crit[0]['title'] if open_crit else 'None'}\n\n"
                         "Recommendation: Focus on RDS connection pool group (INC-001) first — cascading impact.")
            elif any(w in q for w in ["runbook","how to","fix","resolve"]):
                reply = ("I can provide runbooks for: " + ", ".join(RUNBOOKS.keys()) +
                         "\n\nCheck the 📖 Runbooks tab for full step-by-step guides. "
                         "Runbooks are also auto-attached to every Jira ticket I create.")
            elif any(w in q for w in ["correlation","root cause","incident","group"]):
                reply = (f"🔗 I've detected {len(corrs)} incident groups:\n\n" +
                         "\n".join([f"• **{g['group_id']}** — {g['title']} ({g['criticality']}, {g['confidence']}% confidence)" for g in corrs]))
            elif any(w in q for w in ["aws","ec2","rds","lambda","ecs"]):
                aws = generate_aws_data()
                unhealthy = [s for s in aws["ecs"] if s["running"]<s["desired"]]
                reply = (f"☁️ AWS Status:\n- ECS: {sum(s['running'] for s in aws['ecs'])}/{sum(s['desired'] for s in aws['ecs'])} tasks running\n"
                         f"- RDS: {len(aws['rds'])} instances, all available\n"
                         f"- Lambda: {len(aws['lambda'])} functions\n"
                         + (f"\n⚠️ Degraded: {', '.join(s['service'] for s in unhealthy)}" if unhealthy else "\n✅ All services at desired capacity"))
            elif any(w in q for w in ["jira","ticket"]):
                reply = (f"🎫 {len(st.session_state.jira_tickets)} tickets created. "
                         f"{sum(1 for t in st.session_state.jira_tickets if t.get('mode')=='live')} live, "
                         f"{sum(1 for t in st.session_state.jira_tickets if t.get('mode')=='demo')} demo. "
                         "Check the Jira & Email tab for full details including descriptions.")
            else:
                reply = (f"I'm tracking {len(open_crit)} CRITICAL and {len(open_high)} HIGH issues. "
                         "I can help with: incident analysis, runbooks, AWS health, shift handover reports, "
                         "and Jira/notification status. What would you like to know?")
        st.session_state.chat_history.append({"role":"assistant","content":reply})
        audit("AI_QUERY", user_input[:100], "AI")
        st.rerun()
    if st.button("🗑️ Clear Chat"):
        st.session_state.chat_history = []
        st.rerun()


