def render_notifications():
    st.markdown('<div class="page-banner"><h2>🎫 Jira & Notification Log</h2><p>Full audit trail of all auto-created tickets and notifications sent</p></div>', unsafe_allow_html=True)
    t1,t2,t3 = st.tabs([f"🎫 Jira Tickets ({len(st.session_state.jira_tickets)})",
                         f"📧 Email Log ({len(st.session_state.email_log)})",
                         f"💬 Slack/Teams ({sum(1 for e in st.session_state.audit_log if e['category'] in ('SLACK','TEAMS'))})"])
    with t1:
        if not st.session_state.jira_tickets:
            st.info("No tickets yet. System auto-creates for CRITICAL/HIGH issues. Enable 'Auto Jira' in sidebar.")
        else:
            lc,dc = sum(1 for t in st.session_state.jira_tickets if t.get("mode")=="live"), sum(1 for t in st.session_state.jira_tickets if t.get("mode")=="demo")
            c1,c2,c3 = st.columns(3); c1.metric("Total",len(st.session_state.jira_tickets)); c2.metric("Live",lc); c3.metric("Demo",dc)
            for t in reversed(st.session_state.jira_tickets):
                with st.expander(f"🎫 {t['ticket']} — {t['title'][:60]}", expanded=False):
                    col_l,col_r = st.columns([2,1])
                    with col_l:
                        st.markdown(f'<span class="badge-{t.get("criticality","info").lower()}">{t.get("criticality","—")}</span> &nbsp; <span style="font-size:0.72rem;color:#64748B;">📍 {t.get("source","—")} | 🕐 {t.get("created","—")} | {"🟢 LIVE" if t.get("mode")=="live" else "🔵 DEMO"}</span>', unsafe_allow_html=True)
                        st.markdown(f"**Priority:** {t.get('priority','—')} | **Runbook:** {t.get('runbook','—')} | **Owner:** {t.get('runbook_owner','—')}")
                        if t.get("jira_url"): st.markdown(f"🔗 [{t['ticket']}]({t['jira_url']})")
                    with col_r:
                        if t.get("jira_url") and t.get("mode")=="live":
                            st.link_button("Open in Jira ↗", t["jira_url"])
                    st.markdown("**Description sent to Jira:**")
                    st.code(t.get("description","—"), language="text")
    with t2:
        if not st.session_state.email_log:
            st.info("No emails yet. Enable 'Auto Email' in sidebar and configure ALERT_EMAILS in Settings.")
        else:
            for e in reversed(st.session_state.email_log):
                crit = e.get("criticality","INFO")
                with st.expander(f"📧 {e.get('subject','—')[:70]}", expanded=False):
                    st.markdown(f'<span class="badge-{crit.lower()}">{crit}</span> &nbsp; <span style="font-size:0.72rem;color:#64748B;">🕐 {e.get("sent","—")} | {"🟢 SENT" if e.get("mode")=="live" else "🔵 DEMO"}</span>', unsafe_allow_html=True)
                    st.markdown(f"**To:** `{e.get('to','—')}` | **Jira:** `{e.get('jira','—')}`")
                    st.code(e.get("body","—"), language="text")
    with t3:
        slack_teams = [e for e in st.session_state.audit_log if e["category"] in ("SLACK","TEAMS")]
        if not slack_teams:
            st.info("No Slack/Teams notifications yet. Configure webhooks in Settings and enable toggles in sidebar.")
        else:
            for e in reversed(slack_teams):
                st.markdown(f'<div class="audit-row">{"💬" if e["category"]=="SLACK" else "🟣"} <b>{e["category"]}</b> — {e["action"]} — {e["detail"]} — {e["timestamp"]}</div>', unsafe_allow_html=True)


