def render_handover():
    st.markdown('<div class="page-banner"><h2>📋 Shift Handover Report</h2><p>One-click shift summaries — replace 15-20 min manual prep with instant generation</p></div>', unsafe_allow_html=True)
    c1,c2,c3 = st.columns(3)
    with c1: window_h = st.selectbox("Time Window", [8,12,24,48,72], format_func=lambda x: f"Last {x} hours")
    with c2: include_resolved = st.checkbox("Include Resolved Issues", value=True)
    with c3: include_aws = st.checkbox("Include AWS Summary", value=True)

    if st.button("🚀 Generate Handover Report", type="primary"):
        issues  = generate_issues()
        cutoff  = datetime.now() - timedelta(hours=window_h)
        in_window = [i for i in issues if datetime.strptime(i["timestamp"],"%Y-%m-%d %H:%M:%S") >= cutoff]
        open_iss  = [i for i in in_window if i["status"] != "Resolved"]
        res_iss   = [i for i in in_window if i["status"] == "Resolved"] if include_resolved else []
        corrs     = build_correlations()
        aws       = generate_aws_data() if include_aws else None

        crit_open = [i for i in open_iss if i["criticality"]=="CRITICAL"]
        high_open = [i for i in open_iss if i["criticality"]=="HIGH"]

        report_lines = [
            f"AIR CANADA SUPPORT SYSTEM — SHIFT HANDOVER REPORT",
            f"{'='*62}",
            f"Generated:    {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}",
            f"Generated By: {st.session_state.user} ({st.session_state.role})",
            f"Window:       Last {window_h} hours",
            f"{'='*62}",
            "",
            "EXECUTIVE SUMMARY",
            "-"*40,
            f"  Total Issues in Window:  {len(in_window)}",
            f"  Currently Open:          {len(open_iss)}",
            f"    - CRITICAL:            {len(crit_open)}",
            f"    - HIGH:                {len(high_open)}",
            f"    - MEDIUM:              {sum(1 for i in open_iss if i['criticality']=='MEDIUM')}",
            f"    - LOW/INFO:            {sum(1 for i in open_iss if i['criticality'] in ('LOW','INFO'))}",
            f"  Resolved in Window:      {len(res_iss)}",
            f"  Incident Groups:         {len(corrs)}",
            f"  Jira Tickets Created:    {len(st.session_state.jira_tickets)}",
            f"  Emails Sent:             {len(st.session_state.email_log)}",
            "",
        ]
        if crit_open:
            report_lines += ["CRITICAL ISSUES REQUIRING IMMEDIATE ATTENTION", "-"*40]
            for i in crit_open:
                report_lines += [f"  [{i['id']}] {i['title']}", f"    Source: {i['source']} | Detected: {i['timestamp']}",
                                 f"    Jira: {i.get('jira','Not created')}", f"    Status: {i['status']}", ""]
        if corrs:
            report_lines += ["ACTIVE INCIDENT GROUPS (ROOT CAUSE CORRELATION)", "-"*40]
            for g in corrs:
                report_lines += [f"  {g['group_id']}: {g['title']} [{g['criticality']}]",
                                 f"    Root Cause: {g['root_cause']}", f"    Impact: {' → '.join(g['impact_chain'])}",
                                 f"    Confidence: {g['confidence']}%", ""]
        if high_open:
            report_lines += ["HIGH PRIORITY OPEN ISSUES", "-"*40]
            for i in high_open:
                report_lines += [f"  [{i['id']}] {i['title']}",
                                 f"    Source: {i['source']} | Jira: {i.get('jira','Not created')}", ""]
        if res_iss:
            report_lines += ["RESOLVED IN THIS WINDOW", "-"*40]
            for i in res_iss[:10]:
                report_lines += [f"  [{i['id']}] {i['title']} — Resolved at {i.get('resolved_at','unknown')}"]
            if len(res_iss) > 10:
                report_lines.append(f"  ... and {len(res_iss)-10} more")
            report_lines.append("")
        if aws:
            unhealthy_ecs = [s for s in aws["ecs"] if s["running"]<s["desired"]]
            stopped_ec2   = [e for e in aws["ec2"] if e["state"]=="stopped"]
            report_lines += ["AWS INFRASTRUCTURE STATUS", "-"*40,
                f"  EC2: {sum(1 for e in aws['ec2'] if e['state']=='running')}/{len(aws['ec2'])} running",
                f"  RDS: {len(aws['rds'])} instances available",
                f"  ECS: {sum(s['running'] for s in aws['ecs'])}/{sum(s['desired'] for s in aws['ecs'])} tasks running",
                f"  Lambda: {len(aws['lambda'])} functions"]
            if unhealthy_ecs:
                report_lines.append(f"  ⚠️  Degraded ECS: {', '.join(s['service'] for s in unhealthy_ecs)}")
            if stopped_ec2:
                report_lines.append(f"  ⚠️  Stopped EC2: {', '.join(e['name'] for e in stopped_ec2)}")
            report_lines.append("")
        report_lines += [
            "RECOMMENDATIONS FOR INCOMING SHIFT", "-"*40,
            f"  1. {'Address ' + crit_open[0]['title'] + ' immediately (CRITICAL)' if crit_open else 'No CRITICAL issues — system stable'}",
            f"  2. {'Investigate INC-001 (DB cascade) — highest correlated risk' if corrs else 'Monitor open HIGH issues for escalation'}",
            f"  3. Verify Jira coverage: {len(st.session_state.jira_tickets)} tickets vs {len(open_iss)} open issues",
            f"  4. Review AWS ECS task health — auth-service running at 50% desired",
            "", "="*62,
            "Air Canada Support System — Powered by Infosys Travel & Hospitality",
        ]
        report_text = "\n".join(report_lines)
        st.code(report_text, language="text")
        st.download_button("⬇️ Download Report (.txt)", data=report_text,
                           file_name=f"handover_{datetime.now().strftime('%Y%m%d_%H%M')}.txt",
                           mime="text/plain")
        st.session_state.handover_reports.append({
            "generated": datetime.now().strftime("%Y-%m-%d %H:%M"),
            "by": st.session_state.user, "window_h": window_h,
            "open_count": len(open_iss), "resolved_count": len(res_iss),
            "report": report_text,
        })
        audit("HANDOVER_GENERATED", f"Window: {window_h}h, Open: {len(open_iss)}, Resolved: {len(res_iss)}", "REPORT")

    if st.session_state.handover_reports:
        st.markdown("---")
        st.markdown("#### 📂 Previous Reports")
        for r in reversed(st.session_state.handover_reports[-5:]):
            with st.expander(f"Report — {r['generated']} by {r['by']} (Last {r['window_h']}h)", expanded=False):
                st.code(r["report"], language="text")
                st.download_button(f"⬇️ Download", data=r["report"],
                                   file_name=f"handover_{r['generated'].replace(':','').replace(' ','_')}.txt",
                                   mime="text/plain", key=f"dl_{r['generated']}")


