def render_alert_rules():
    st.markdown('<div class="page-banner"><h2>🔔 Alert Rules</h2><p>Configure thresholds — system auto-creates issues, Jira & notifications when rules trigger</p></div>', unsafe_allow_html=True)
    st.markdown(f"**{sum(1 for r in st.session_state.alert_rules if r['enabled'])} of {len(st.session_state.alert_rules)} rules enabled**")
    for idx, rule in enumerate(st.session_state.alert_rules):
        color = CRIT_COLORS.get(rule["criticality"],"#888")
        status_icon = "🟢" if rule["enabled"] else "🔴"
        with st.expander(f"{status_icon} {rule['name']} → {rule['criticality']}", expanded=False):
            c1,c2,c3 = st.columns(3)
            with c1:
                st.markdown(f"**Service:** `{rule['service']}`")
                st.markdown(f"**Log Level:** `{rule['level']}`")
                st.markdown(f"**Threshold:** {rule['threshold']} occurrences in {rule['window_min']} min")
            with c2:
                st.markdown(f"**Creates Issue:** <span class='badge-{rule['criticality'].lower()}'>{rule['criticality']}</span>", unsafe_allow_html=True)
                st.markdown(f"**Auto Jira:** {'✅' if rule['action_jira'] else '❌'}")
                st.markdown(f"**Auto Email:** {'✅' if rule['action_email'] else '❌'}")
                st.markdown(f"**Auto Slack:** {'✅' if rule['action_slack'] else '❌'}")
            with c3:
                if st.button(f"{'🔴 Disable' if rule['enabled'] else '🟢 Enable'}", key=f"rule_toggle_{idx}"):
                    st.session_state.alert_rules[idx]["enabled"] = not rule["enabled"]
                    audit("RULE_TOGGLED", f"{rule['name']} {'disabled' if rule['enabled'] else 'enabled'}", "RULE")
                    st.rerun()
                if st.button("🧪 Test Rule", key=f"rule_test_{idx}"):
                    st.info(f"✅ Simulated: Rule '{rule['name']}' would create a {rule['criticality']} issue and trigger {'Jira' if rule['action_jira'] else ''} {'Email' if rule['action_email'] else ''} {'Slack' if rule['action_slack'] else ''}")
    st.markdown("---")
    st.markdown("#### ➕ Create New Alert Rule")
    if st.session_state.role in ["Admin","Manager"]:
        with st.expander("Define new rule", expanded=False):
            rc1,rc2 = st.columns(2)
            with rc1:
                r_name  = st.text_input("Rule Name", key="new_rule_name")
                r_svc   = st.selectbox("Service", ["any","booking-engine","payment-gateway","auth-service","api-gateway","lambda-processor","ecs-worker"], key="new_rule_svc")
                r_level = st.selectbox("Log Level", ["ERROR","WARN","INFO"], key="new_rule_level")
            with rc2:
                r_thresh = st.number_input("Occurrences Threshold", 1, 1000, 5, key="new_rule_thresh")
                r_window = st.number_input("Window (minutes)", 1, 60, 5, key="new_rule_window")
                r_crit   = st.selectbox("Issue Criticality", list(CRIT_COLORS.keys()), key="new_rule_crit")
            ra1,ra2,ra3 = st.columns(3)
            with ra1: r_jira  = st.checkbox("Auto Jira",  value=True,  key="new_rule_jira")
            with ra2: r_email = st.checkbox("Auto Email", value=True,  key="new_rule_email")
            with ra3: r_slack = st.checkbox("Auto Slack", value=False, key="new_rule_slack")
            if st.button("💾 Create Rule") and r_name:
                new_rule = {"id":f"rule-{len(st.session_state.alert_rules)+1:03d}","name":r_name,"enabled":True,
                            "service":r_svc,"level":r_level,"threshold":r_thresh,"window_min":r_window,
                            "criticality":r_crit,"action_jira":r_jira,"action_email":r_email,"action_slack":r_slack}
                st.session_state.alert_rules.append(new_rule)
                audit("RULE_CREATED", f"{r_name} — {r_crit}", "RULE")
                st.success(f"✅ Rule '{r_name}' created")
                st.rerun()
    else:
        st.warning("Admin or Manager role required to create rules.")


