# TAB: AUDIT TRAIL
# ══════════════════════════════════════════════════════════════════════════════

def render_audit_trail():
    st.markdown('<div class="page-banner"><h2>🕐 Audit Trail</h2><p>Complete activity log — who did what and when</p></div>', unsafe_allow_html=True)
    if not st.session_state.audit_log:
        st.info("No audit events yet. Actions (login, Jira creation, email, resolve, etc.) will appear here.")
        return
    df_audit = pd.DataFrame(st.session_state.audit_log)
    c1,c2,c3,c4 = st.columns(4)
    with c1: cat_filter  = st.multiselect("Category", df_audit["category"].unique().tolist(), default=df_audit["category"].unique().tolist(), key="audit_cat")
    with c2: user_filter = st.multiselect("User", df_audit["user"].unique().tolist(), default=df_audit["user"].unique().tolist(), key="audit_user")
    with c3: act_search  = st.text_input("🔍 Search action/detail", key="audit_search")
    with c4: show_last   = st.selectbox("Show last", [50,100,200,"All"], index=1, key="audit_show")
    filtered = df_audit[df_audit["category"].isin(cat_filter) & df_audit["user"].isin(user_filter)]
    if act_search:
        filtered = filtered[filtered["action"].str.contains(act_search,case=False,na=False) |
                            filtered["detail"].str.contains(act_search,case=False,na=False)]
    if show_last != "All":
        filtered = filtered.tail(int(show_last))
    cat_colors = {"AUTH":"#1565C0","JIRA":"#2E7D32","EMAIL":"#F57C00","SLACK":"#4A148C","TEAMS":"#880E4F",
                  "INCIDENT":"#C62828","RULE":"#00695C","AI":"#6A1B9A","INGESTION":"#004D40","REPORT":"#1A237E","RUNBOOK":"#BF360C","SYSTEM":"#424242"}
    st.markdown(f"**{len(filtered)} events**")
    for _, row in filtered.iloc[::-1].iterrows():
        color = cat_colors.get(row["category"],"#888")
        st.markdown(f'<div class="audit-row"><span style="background:{color};color:white;padding:1px 6px;border-radius:4px;font-size:0.68rem;font-weight:700;">{row["category"]}</span> &nbsp; <b>{row["action"]}</b> &nbsp; <span style="color:#94A3B8;">{row["detail"]}</span> &nbsp; <span style="float:right;color:#94A3B8;">{row["user"]} · {row["timestamp"]}</span></div>', unsafe_allow_html=True)
    st.markdown("---")
    if st.button("📊 Export Audit Log (CSV)"):
        csv = df_audit.to_csv(index=False)
        st.download_button("⬇️ Download CSV", data=csv,
                           file_name=f"audit_log_{datetime.now().strftime('%Y%m%d_%H%M')}.csv",
                           mime="text/csv")


