def render_user_management():
    st.markdown('<div class="page-banner"><h2>👥 User Management</h2><p>Manage roles and permissions</p></div>', unsafe_allow_html=True)
    if st.session_state.role != "Admin":
        st.warning("⚠️ Admin access required.")
        return
    users_data = [{"Username":u,"Name":v["name"],"Role":v["role"],"Status":"Active"} for u,v in USERS.items()]
    st.dataframe(pd.DataFrame(users_data), use_container_width=True, hide_index=True)
    st.markdown("---")
    st.markdown("#### 🔐 Role Permissions Matrix")
    perms = [
        {"Role":"Admin",  "Issues":"✅","Resolve":"✅","Create Jira":"✅","Send Email":"✅","Alert Rules":"✅","Runbooks":"✅","User Mgmt":"✅","Settings":"✅"},
        {"Role":"Manager","Issues":"✅","Resolve":"✅","Create Jira":"✅","Send Email":"✅","Alert Rules":"✅","Runbooks":"✅","User Mgmt":"❌","Settings":"✅"},
        {"Role":"Analyst","Issues":"✅","Resolve":"❌","Create Jira":"✅","Send Email":"✅","Alert Rules":"❌","Runbooks":"✅","User Mgmt":"❌","Settings":"❌"},
        {"Role":"Viewer", "Issues":"✅","Resolve":"❌","Create Jira":"❌","Send Email":"❌","Alert Rules":"❌","Runbooks":"✅","User Mgmt":"❌","Settings":"❌"},
    ]
    st.dataframe(pd.DataFrame(perms), use_container_width=True, hide_index=True)


